interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

const PROCESSING_FEE = 5;
const EMPTY_QUOTE_PREMIUM = PROCESSING_FEE;
const SINGLE_SWORD_PREMIUM = 115;

const quoteStep = (step: QuoteStep): QuoteResult => {
  if (step.items.length === 0) return { premium: EMPTY_QUOTE_PREMIUM };
  return { premium: SINGLE_SWORD_PREMIUM };
};

export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};
